int *alloc_zeros(int n);

void test_alloc_zeros_not_null(void) {
    int *arr = alloc_zeros(5);
    TEST_ASSERT_NOT_NULL(arr);
    free(arr);
}

void test_alloc_zeros_initialized(void) {
    int *arr = alloc_zeros(4);
    TEST_ASSERT_NOT_NULL(arr);
    TEST_ASSERT_EQUAL_INT(0, arr[0]);
    TEST_ASSERT_EQUAL_INT(0, arr[1]);
    TEST_ASSERT_EQUAL_INT(0, arr[3]);
    free(arr);
}

void test_alloc_zeros_can_write(void) {
    int *arr = alloc_zeros(3);
    TEST_ASSERT_NOT_NULL(arr);
    arr[0] = 10; arr[1] = 20; arr[2] = 30;
    TEST_ASSERT_EQUAL_INT(10, arr[0]);
    TEST_ASSERT_EQUAL_INT(20, arr[1]);
    TEST_ASSERT_EQUAL_INT(30, arr[2]);
    free(arr);
}

void test_alloc_zeros_large(void) {
    int *arr = alloc_zeros(100);
    TEST_ASSERT_NOT_NULL(arr);
    TEST_ASSERT_EQUAL_INT(0, arr[50]);
    TEST_ASSERT_EQUAL_INT(0, arr[99]);
    free(arr);
}

int main(void) {
    RUN_TEST(test_alloc_zeros_not_null);
    RUN_TEST(test_alloc_zeros_initialized);
    RUN_TEST(test_alloc_zeros_can_write);
    RUN_TEST(test_alloc_zeros_large);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

